class Solution:
    def lexSmallest(self, s):
        n = len(s)
        best = None
        for k in range(1, n + 1):
            a = s[:k][::-1] + s[k:]
            b = s[:n - k] + s[n - k:][::-1]
            for cand in (a, b):
                if best is None or cand < best:
                    best = cand
        return best

