class Solution:
    def lexSmallest(self, s):
        n = len(s)
        best = s
        for k in range(1, n + 1):
            pre = s[:k][::-1] + s[k:]
            if pre < best:
                best = pre
            suf = s[:n - k] + s[n - k:][::-1]
            if suf < best:
                best = suf
        return best

