var lexSmallest = function(s) {
    const n = s.length;
    let best = s;
    for (let k = 1; k <= n; k++) {
        const pre = s.slice(0, k).split('').reverse().join('') + s.slice(k);
        if (pre < best) best = pre;
        const suf = s.slice(0, n - k) + s.slice(n - k).split('').reverse().join('');
        if (suf < best) best = suf;
    }
    return best;
};
